class Solution {
    public String greatestLetter(String s) {
        String result = "";
        for (char c = 'A'; c <= 'Z'; c++) {
            if (s.toLowerCase().contains(String.valueOf(c)) && s.contains(String.valueOf(c))) {
                result = String.valueOf(c);
                break;
            }
        }
        return result;
    }
}
